/**
 * OAuth Router
 *
 * API routes for OAuth authentication.
 */

import { Router, json } from 'express';
import type { Request, Response } from 'express';
import { rateLimit } from 'express-rate-limit';
import { doubleCsrf } from 'csrf-csrf';
import cookieParser from 'cookie-parser';
import type { SessionManager } from '../session.js';
import type { MPCAccountManager } from '../mpc.js';
import type { IPFSRecoveryManager } from '../recovery/ipfs.js';
import type { DatabaseAdapter, OAuthConfig, OAuthProvider, RateLimitConfig, CsrfConfig, AnonAuthHooks, AfterAuthSuccessCtx } from '../../types/index.js';
import type { EmailService } from '../email.js';
import { createOAuthManager, type OAuthManager, type OAuthProfile } from './index.js';
import pino from 'pino';
import type { Logger } from 'pino';
import { wrapAnalytics } from '../analytics.js';
import { validateBody } from '../validation/validateBody.js';
import {
  oauthCallbackBodySchema,
  oauthLinkBodySchema,
} from '../validation/schemas.js';

export interface OAuthRouterConfig {
  db: DatabaseAdapter;
  sessionManager: SessionManager;
  mpcManager: MPCAccountManager;
  oauthConfig: OAuthConfig;
  ipfsRecovery?: IPFSRecoveryManager;
  /** Optional pino logger instance. If omitted, logging is disabled (no output). */
  logger?: Logger;
  /** Optional rate limiting config */
  rateLimiting?: RateLimitConfig;
  /** Optional CSRF config (Double Submit Cookie) */
  csrf?: CsrfConfig;
  /** Optional email service for sending recovery passwords */
  emailService?: EmailService;
  /** Optional pre-created OAuthManager instance. If omitted, one is created internally. */
  oauthManager?: OAuthManager;
  /** Phase 11 scaffolding — accepted and stored; call sites wired in Phases 13–15. */
  hooks?: AnonAuthHooks;
  /** Phase 13 ANALYTICS-01. Primary RP ID, used in every emitted event's
   *  `rpId` field. Captured once at router construction. */
  rpId?: string;
  /** Phase 13 ANALYTICS-04. When true, lifecycle emit calls await the
   *  consumer's `onAuthEvent` hook before responding. Default false. */
  awaitAnalytics?: boolean;
}

export function createOAuthRouter(config: OAuthRouterConfig): Router {
  const log = (config.logger ?? pino({ level: 'silent' })).child({ module: 'oauth' });
  const router = Router();
  const {
    db,
    sessionManager,
    mpcManager,
    oauthConfig,
    ipfsRecovery,
    emailService,
  } = config;

  // Phase 13 ANALYTICS-01/04: capture rpId + emit closure ONCE at factory
  // construction (Pitfall 2 — never per-request). Mirrors src/server/router.ts.
  const rpId = config.rpId ?? 'localhost';
  const emit = wrapAnalytics(config.hooks?.onAuthEvent, {
    logger: config.logger,
    await: config.awaitAnalytics === true,
  });

  // ░░ Phase 14 HOOK-04 — local helper, encapsulates the 3 IDENTICAL fire blocks ░░
  // The 3 OAuth branches (existing-same-provider, link-by-email, new-user) have
  // IDENTICAL ctx shape and IDENTICAL hook handling. Drift across branches is a
  // correctness risk (RESEARCH §Pattern 7) — this helper enforces lockstep by
  // construction. Returns:
  //   - undefined on `continue: true` OR no hook configured (caller proceeds with
  //     standard createSession + response)
  //   - { status, body } on `continue: false` (caller short-circuits with HOOK-05
  //     response shape; MUST skip createSession to avoid Set-Cookie leak T-14-02)
  //
  // Pitfall 7 (T-14-07): handles `hook === undefined` so callers can pass
  //   `config.hooks?.afterAuthSuccess` directly.
  // Pitfall 8 (T-14-08): awaits the hook explicitly.
  async function runOAuthHook(
    hook: AnonAuthHooks['afterAuthSuccess'],
    ctx: Extract<AfterAuthSuccessCtx, { authMethod: `oauth-${string}` }>,
  ): Promise<{ status: number; body: Record<string, unknown> } | undefined> {
    if (!hook) return undefined;
    const result = await hook(ctx);
    if (result.continue === true) return undefined;
    return { status: result.status, body: result.body };
  }

  // Create rate limiter instance
  const authRateConfig = config.rateLimiting?.auth ?? {};
  const authLimiter = rateLimit({
    windowMs: authRateConfig.windowMs ?? 15 * 60 * 1000,
    limit: authRateConfig.limit ?? 20,
    standardHeaders: 'draft-8',
    legacyHeaders: false,
    handler: (_req, res, _next, options) => {
      log.warn({ limit: options.limit }, 'auth rate limit exceeded');
      res.status(429).json({ error: 'Too many requests. Please try again later.' });
    },
  });

  // cookieParser mounted unconditionally — OAuth callback needs req.cookies
  // regardless of CSRF config; CSRF middleware also depends on it
  router.use(cookieParser());

  // CSRF protection (opt-in via config.csrf) with OAuth callback exemption
  if (config.csrf) {
    const { doubleCsrfProtection } = doubleCsrf({
      getSecret: () => config.csrf!.secret,
      getSessionIdentifier: (req) => req.ip ?? '',
      cookieName: '__Host-csrf',
      cookieOptions: {
        httpOnly: true,
        sameSite: 'strict',
        secure: true,
        path: '/',
      },
      ignoredMethods: ['GET', 'HEAD', 'OPTIONS'],
      getCsrfTokenFromRequest: (req) => req.headers['x-csrf-token'] as string,
      // OAuth callback arrives cross-origin from provider; cannot carry CSRF cookie.
      // OAuth flow uses state parameter validation as its own CSRF defense.
      skipCsrfProtection: (req) => {
        return /^\/[^/]+\/callback$/.test(req.path);
      },
    });

    // cookieParser already mounted above
    router.use(doubleCsrfProtection);

    log.info('CSRF protection enabled for OAuth router (callback exempt)');
  }

  // Use injected OAuthManager or create one
  const oauthManager = config.oauthManager ?? createOAuthManager(
    {
      google: oauthConfig.google,
      github: oauthConfig.github,
      twitter: oauthConfig.twitter,
    },
    db
  );

  router.use(json());

  // ============================================
  // OAuth Provider Info
  // ============================================

  /**
   * GET /oauth/providers
   * Get available OAuth providers
   */
  router.get('/providers', (_req: Request, res: Response) => {
    res.json({
      providers: {
        google: oauthManager.isConfigured('google'),
        github: oauthManager.isConfigured('github'),
        twitter: oauthManager.isConfigured('twitter'),
      },
    });
  });

  // ============================================
  // OAuth Flow Start
  // ============================================

  /**
   * GET /oauth/:provider/start
   * Start OAuth flow for a provider
   */
  router.get('/:provider/start', authLimiter, async (req: Request, res: Response) => {
    try {
      const provider = req.params.provider as 'google' | 'github' | 'twitter';

      if (!['google', 'github', 'twitter'].includes(provider)) {
        return res.status(400).json({ error: 'Invalid provider' });
      }

      if (!oauthManager.isConfigured(provider)) {
        return res.status(400).json({ error: `${provider} OAuth not configured` });
      }

      const redirectUri = `${oauthConfig.callbackBaseUrl}/${provider}`;
      const { url, state, codeVerifier } = await oauthManager.getAuthUrl(provider, redirectUri);

      // Store code verifier in session/cookie for PKCE
      if (codeVerifier) {
        res.cookie('oauth_code_verifier', codeVerifier, {
          httpOnly: true,
          secure: process.env.NODE_ENV === 'production',
          sameSite: 'lax',
          maxAge: 10 * 60 * 1000, // 10 minutes
        });
      }

      res.cookie('oauth_state', state, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'lax',
        maxAge: 10 * 60 * 1000,
      });

      return res.json({ url, state });
    } catch (error) {
      log.error({ err: error }, 'OAuth start error');
      return res.status(500).json({ error: 'Failed to start OAuth flow' });
    }
  });

  // ============================================
  // OAuth Callback
  // ============================================

  /**
   * POST /oauth/:provider/callback
   * Handle OAuth callback
   */
  router.post('/:provider/callback', authLimiter, async (req: Request, res: Response) => {
    try {
      // INFRA-05: Detect missing cookie-parser middleware
      if (req.cookies === undefined) {
        log.error(
          'OAuth callback received request without req.cookies. ' +
          'Mount cookie-parser middleware before the OAuth router: app.use(cookieParser())'
        );
        return res.status(500).json({
          error: 'Server configuration error: cookie-parser middleware is required',
        });
      }

      const body = validateBody(oauthCallbackBodySchema, req, res);
      if (!body) return;

      const provider = req.params.provider as 'google' | 'github' | 'twitter';
      const { code, state } = body;

      // DB-backed state validation — atomic lookup + delete (replay protection)
      const oauthState = await oauthManager.validateState(state);
      if (!oauthState) {
        return res.status(400).json({ error: 'Invalid state' });
      }
      const codeVerifier = oauthState.codeVerifier;
      // Clear cookies for hygiene — they are no longer consulted for validation
      res.clearCookie('oauth_state');
      res.clearCookie('oauth_code_verifier');

      // Exchange code for tokens
      const redirectUri = `${oauthConfig.callbackBaseUrl}/${provider}`;
      const tokens = await oauthManager.exchangeCode(provider, code, redirectUri, codeVerifier);

      // Get user profile
      const profile = await oauthManager.getProfile(provider, tokens.accessToken);

      // Check if user exists with this provider
      let user = await db.getOAuthUserByProvider(provider, profile.providerId);

      if (user) {
        // ░░ Phase 14 HOOK-04 fire point — Branch 1 (existing user, same provider) ░░
        const sf = await runOAuthHook(config.hooks?.afterAuthSuccess, {
          authMethod: `oauth-${provider}` as const,
          userId: user.id,
          nearAccountId: user.nearAccountId,
          provider,
          req,
        });

        if (sf) {
          // Pitfall 4 Option A: oauth.callback.success fires regardless of short-circuit.
          await emit({ type: 'oauth.callback.success', rpId, timestamp: Date.now(), provider });
          // HOOK-05 short-circuit. NO Set-Cookie because createSession is skipped (T-14-02).
          return res.status(sf.status).json({ ...sf.body, secondFactor: sf });
        }

        // Existing user - update last active and create session
        await sessionManager.createSession(user.id, res, {
          ipAddress: req.ip,
          userAgent: req.headers['user-agent'],
        });

        await emit({ type: 'oauth.callback.success', rpId, timestamp: Date.now(), provider });

        return res.json({
          success: true,
          user: {
            id: user.id,
            email: user.email,
            name: user.name,
            avatarUrl: user.avatarUrl,
            nearAccountId: user.nearAccountId,
            type: 'standard',
          },
          isNewUser: false,
        });
      }

      // Check if user exists with this email (link accounts)
      if (profile.email) {
        user = await db.getOAuthUserByEmail(profile.email);
        if (user) {
          // Link this provider to existing account
          const providerData: OAuthProvider = {
            provider,
            providerId: profile.providerId,
            email: profile.email,
            name: profile.name,
            avatarUrl: profile.avatarUrl,
            connectedAt: new Date(),
          };
          await db.linkOAuthProvider(user.id, providerData);

          // ░░ Phase 14 HOOK-04 fire point — Branch 2 (link by email) ░░
          const sf = await runOAuthHook(config.hooks?.afterAuthSuccess, {
            authMethod: `oauth-${provider}` as const,
            userId: user.id,
            nearAccountId: user.nearAccountId,
            provider,
            req,
          });

          if (sf) {
            await emit({ type: 'oauth.callback.success', rpId, timestamp: Date.now(), provider });
            return res.status(sf.status).json({ ...sf.body, secondFactor: sf });
          }

          await sessionManager.createSession(user.id, res, {
            ipAddress: req.ip,
            userAgent: req.headers['user-agent'],
          });

          await emit({ type: 'oauth.callback.success', rpId, timestamp: Date.now(), provider });

          return res.json({
            success: true,
            user: {
              id: user.id,
              email: user.email,
              name: user.name,
              avatarUrl: user.avatarUrl,
              nearAccountId: user.nearAccountId,
              type: 'standard',
            },
            isNewUser: false,
            linkedProvider: provider,
          });
        }
      }

      // New user - create account with MPC
      const tempUserId = crypto.randomUUID();
      const mpcAccount = await mpcManager.createAccount(tempUserId);

      const providerData: OAuthProvider = {
        provider,
        providerId: profile.providerId,
        email: profile.email,
        name: profile.name,
        avatarUrl: profile.avatarUrl,
        connectedAt: new Date(),
      };

      const newUser = await db.createOAuthUser({
        email: profile.email || `${profile.providerId}@${provider}.oauth`,
        name: profile.name,
        avatarUrl: profile.avatarUrl,
        nearAccountId: mpcAccount.nearAccountId,
        mpcPublicKey: mpcAccount.mpcPublicKey,
        derivationPath: mpcAccount.derivationPath,
        provider: providerData,
      });

      // Create IPFS recovery backup automatically for OAuth users
      if (ipfsRecovery && profile.email) {
        try {
          const recoveryPassword = crypto.randomUUID(); // Auto-generated, sent to email
          const { cid } = await ipfsRecovery.createRecoveryBackup(
            {
              userId: newUser.id,
              nearAccountId: newUser.nearAccountId,
              derivationPath: newUser.derivationPath,
              createdAt: Date.now(),
            },
            recoveryPassword
          );

          await db.storeRecoveryData({
            userId: newUser.id,
            type: 'ipfs',
            reference: cid,
            createdAt: new Date(),
          });

          log.info({ cid }, 'Recovery backup created for new user');

          // Send recovery password to user's email
          if (emailService && profile.email) {
            try {
              await emailService.sendRecoveryPassword(profile.email, recoveryPassword);
            } catch (emailErr) {
              // Email failure should not fail the registration
              log.warn({ err: emailErr }, 'Recovery email send failed — user registered but password not emailed');
            }
          } else if (!emailService) {
            log.info('Email service not configured — recovery password not sent');
          }
        } catch (error) {
          log.error({ err: error }, 'Failed to create recovery backup');
        }
      }

      // ░░ Phase 14 HOOK-04 fire point — Branch 3 (new user) ░░
      // HARSHEST orphan trade-off in v0.7.0: NO transaction wrapper. A hook throw or
      // continue:false leaves user (db.createOAuthUser at line ~315), MPC account
      // (mpcManager.createAccount at line ~304), AND IPFS recovery blob (db.storeRecoveryData
      // at line ~339) ALL committed. README in Plan 14-04 documents this verbatim
      // (RESEARCH §Pitfall 6 / T-14-04). Mitigation: idempotent + non-throwing hooks.
      const sf = await runOAuthHook(config.hooks?.afterAuthSuccess, {
        authMethod: `oauth-${provider}` as const,
        userId: newUser.id,
        nearAccountId: newUser.nearAccountId,
        provider,
        req,
      });

      if (sf) {
        await emit({ type: 'oauth.callback.success', rpId, timestamp: Date.now(), provider });
        return res.status(sf.status).json({ ...sf.body, secondFactor: sf });
      }

      // Create session
      await sessionManager.createSession(newUser.id, res, {
        ipAddress: req.ip,
        userAgent: req.headers['user-agent'],
      });

      await emit({ type: 'oauth.callback.success', rpId, timestamp: Date.now(), provider });

      return res.json({
        success: true,
        user: {
          id: newUser.id,
          email: newUser.email,
          name: newUser.name,
          avatarUrl: newUser.avatarUrl,
          nearAccountId: newUser.nearAccountId,
          type: 'standard',
        },
        isNewUser: true,
      });
    } catch (error) {
      log.error({ err: error }, 'OAuth callback error');
      return res.status(500).json({ error: 'OAuth authentication failed' });
    }
  });

  // ============================================
  // Link Additional Provider
  // ============================================

  /**
   * POST /oauth/:provider/link
   * Link additional OAuth provider to existing account
   */
  router.post('/:provider/link', authLimiter, async (req: Request, res: Response) => {
    try {
      const session = await sessionManager.getSession(req);
      if (!session) {
        return res.status(401).json({ error: 'Authentication required' });
      }

      const body = validateBody(oauthLinkBodySchema, req, res);
      if (!body) return;

      const provider = req.params.provider as 'google' | 'github' | 'twitter';
      const { code, state, codeVerifier } = body;

      // Exchange code for tokens
      const redirectUri = `${oauthConfig.callbackBaseUrl}/${provider}`;
      const tokens = await oauthManager.exchangeCode(provider, code, redirectUri, codeVerifier);

      // Get user profile
      const profile = await oauthManager.getProfile(provider, tokens.accessToken);

      // Check if this provider is already linked to another account
      const existingUser = await db.getOAuthUserByProvider(provider, profile.providerId);
      if (existingUser && existingUser.id !== session.userId) {
        return res.status(400).json({ error: 'This account is already linked to another user' });
      }

      // Link provider to current user
      const providerData: OAuthProvider = {
        provider,
        providerId: profile.providerId,
        email: profile.email,
        name: profile.name,
        avatarUrl: profile.avatarUrl,
        connectedAt: new Date(),
      };

      await db.linkOAuthProvider(session.userId, providerData);

      return res.json({
        success: true,
        message: `${provider} account linked successfully`,
      });
    } catch (error) {
      log.error({ err: error }, 'OAuth link error');
      return res.status(500).json({ error: 'Failed to link provider' });
    }
  });

  return router;
}
