/**
 * Passkey (WebAuthn) Authentication
 * 
 * Handles passkey registration and authentication using @simplewebauthn/server
 */

import {
  generateRegistrationOptions,
  verifyRegistrationResponse,
  generateAuthenticationOptions,
  verifyAuthenticationResponse,
} from '@simplewebauthn/server';
import type {
  GenerateRegistrationOptionsOpts,
  GenerateAuthenticationOptionsOpts,
  VerifyRegistrationResponseOpts,
  VerifyAuthenticationResponseOpts,
  VerifiedRegistrationResponse,
  VerifiedAuthenticationResponse,
} from '@simplewebauthn/server';
import { randomUUID } from 'crypto';
import pino from 'pino';
import type { Logger } from 'pino';
import type {
  DatabaseAdapter,
  Challenge,
  Passkey,
  CreatePasskeyInput,
  PublicKeyCredentialCreationOptionsJSON,
  PublicKeyCredentialRequestOptionsJSON,
  RegistrationResponseJSON,
  AuthenticationResponseJSON,
  AuthenticatorTransport,
  RelatedOrigin,                  // Phase 12 RPID-01
} from '../types/index.js';

export interface PasskeyConfig {
  /** Relying Party name (shown to users) */
  rpName: string;
  /** Relying Party ID (your domain, e.g., 'example.com') */
  rpId: string;
  /** Origin for WebAuthn (e.g., 'https://example.com') */
  origin: string;
  /** Phase 12 RPID-01 — already-validated paired tuples threaded from
   *  createAnonAuth. REQUIRED (factory passes [] when consumer omits
   *  rp.relatedOrigins). The validator runs upstream (src/server/index.ts
   *  startup); this field is never re-validated here. Spread by tuple
   *  ORDER into expectedOrigin / expectedRPID at the verify call sites
   *  — no intermediate `.filter()` / `.sort()` permitted (Pitfall 1). */
  relatedOrigins: readonly RelatedOrigin[];
  /** Challenge timeout in ms (default: 60000) */
  challengeTimeoutMs?: number;
  /** Optional pino logger instance. If omitted, logging is disabled (no output). */
  logger?: Logger;
}

export interface PasskeyManager {
  startRegistration(
    userId: string,
    userDisplayName: string
  ): Promise<{
    challengeId: string;
    options: PublicKeyCredentialCreationOptionsJSON;
  }>;
  
  finishRegistration(
    challengeId: string,
    response: RegistrationResponseJSON
  ): Promise<{
    verified: boolean;
    passkeyData?: {
      credentialId: string;
      publicKey: Uint8Array;
      counter: number;
      deviceType: 'singleDevice' | 'multiDevice';
      backedUp: boolean;
      transports?: AuthenticatorTransport[];
    };
    tempUserId?: string;
  }>;
  
  startAuthentication(
    userId?: string
  ): Promise<{
    challengeId: string;
    options: PublicKeyCredentialRequestOptionsJSON;
  }>;
  
  finishAuthentication(
    challengeId: string,
    response: AuthenticationResponseJSON
  ): Promise<{
    verified: boolean;
    userId?: string;
    passkey?: Passkey;
    /** Fresh BE/BS values re-read from the assertion (not the stored DB row).
     *  Present when verification succeeded; consumed by router for response surface. */
    passkeyData?: {
      backedUp: boolean;
      deviceType: 'singleDevice' | 'multiDevice';
    };
  }>;
}

/**
 * Create passkey manager
 */
export function createPasskeyManager(
  db: DatabaseAdapter,
  config: PasskeyConfig
): PasskeyManager {
  const log = (config.logger ?? pino({ level: 'silent' })).child({ module: 'passkey' });
  const challengeTimeoutMs = config.challengeTimeoutMs || 60000;

  return {
    async startRegistration(userId, userDisplayName) {
      // For registration, userId is a temp ID - user doesn't exist yet
      // We store it in metadata, not as a foreign key
      
      const options = await generateRegistrationOptions({
        rpName: config.rpName,
        rpID: config.rpId,
        userName: userDisplayName,
        userDisplayName: userDisplayName,
        userID: new TextEncoder().encode(userId),
        attestationType: 'none',
        excludeCredentials: [], // No existing passkeys for new user
        authenticatorSelection: {
          residentKey: 'required',  // Required for discoverable credentials (login without username)
          userVerification: 'preferred',
          // Note: removed authenticatorAttachment to allow both platform and cross-platform (hardware keys)
        },
      } as GenerateRegistrationOptionsOpts);
      
      // Store challenge - userId goes in metadata since user doesn't exist yet
      const challengeId = randomUUID();
      const challenge: Challenge = {
        id: challengeId,
        challenge: options.challenge,
        type: 'registration',
        userId: undefined, // Don't set foreign key - user doesn't exist
        expiresAt: new Date(Date.now() + challengeTimeoutMs),
        metadata: { tempUserId: userId, userDisplayName }, // Store temp ID here
      };
      
      await db.storeChallenge(challenge);
      
      return {
        challengeId,
        options: options as unknown as PublicKeyCredentialCreationOptionsJSON,
      };
    },
    
    async finishRegistration(challengeId, response) {
      // Get and validate challenge
      const challenge = await db.getChallenge(challengeId);
      
      if (!challenge) {
        throw new Error('Challenge not found or expired');
      }
      
      if (challenge.type !== 'registration') {
        throw new Error('Invalid challenge type');
      }
      
      if (challenge.expiresAt < new Date()) {
        await db.deleteChallenge(challengeId);
        throw new Error('Challenge expired');
      }
      
      // Get temp user ID from metadata (for registration, user doesn't exist yet)
      const tempUserId = challenge.metadata?.tempUserId as string | undefined;
      if (!tempUserId) {
        throw new Error('Challenge missing temp user ID');
      }
      
      // Verify registration
      let verification: VerifiedRegistrationResponse;
      try {
        verification = await verifyRegistrationResponse({
          response: response as unknown as Parameters<typeof verifyRegistrationResponse>[0]['response'],
          expectedChallenge: challenge.challenge,
          expectedOrigin: config.relatedOrigins.length === 0
            ? config.origin
            : [config.origin, ...config.relatedOrigins.map(r => r.origin)],
          expectedRPID: config.relatedOrigins.length === 0
            ? config.rpId
            : [config.rpId, ...config.relatedOrigins.map(r => r.rpId)],
        } as VerifyRegistrationResponseOpts);
      } catch (error) {
        log.error({ err: error }, 'Registration verification failed');
        await db.deleteChallenge(challengeId);
        return { verified: false };
      }
      
      if (!verification.verified || !verification.registrationInfo) {
        await db.deleteChallenge(challengeId);
        return { verified: false };
      }
      
      const { registrationInfo } = verification;
      
      // Clean up challenge
      await db.deleteChallenge(challengeId);
      
      // Return verified data - caller must create user first, then passkey
      // We return the passkey data but don't save it yet (user doesn't exist)
      return {
        verified: true,
        passkeyData: {
          credentialId: registrationInfo.credential.id,
          publicKey: registrationInfo.credential.publicKey,
          counter: registrationInfo.credential.counter,
          deviceType: registrationInfo.credentialDeviceType,
          backedUp: registrationInfo.credentialBackedUp,
          transports: response.response.transports,
        },
        tempUserId,
      };
    },
    
    async startAuthentication(userId) {
      // Get user's passkeys if userId provided
      let allowCredentials: Array<{
        id: string;
        type: 'public-key';
        transports?: AuthenticatorTransport[];
      }> | undefined;
      
      if (userId) {
        const passkeys = await db.getPasskeysByUserId(userId);
        allowCredentials = passkeys.map((pk) => ({
          id: pk.credentialId,
          type: 'public-key' as const,
          transports: pk.transports,
        }));
      }
      
      const options = await generateAuthenticationOptions({
        rpID: config.rpId,
        userVerification: 'preferred',
        allowCredentials,
      } as GenerateAuthenticationOptionsOpts);
      
      // Store challenge
      const challengeId = randomUUID();
      const challenge: Challenge = {
        id: challengeId,
        challenge: options.challenge,
        type: 'authentication',
        userId,
        expiresAt: new Date(Date.now() + challengeTimeoutMs),
      };
      
      await db.storeChallenge(challenge);
      
      return {
        challengeId,
        options: options as unknown as PublicKeyCredentialRequestOptionsJSON,
      };
    },
    
    async finishAuthentication(challengeId, response) {
      // Get and validate challenge
      const challenge = await db.getChallenge(challengeId);
      
      if (!challenge) {
        throw new Error('Challenge not found or expired');
      }
      
      if (challenge.type !== 'authentication') {
        throw new Error('Invalid challenge type');
      }
      
      if (challenge.expiresAt < new Date()) {
        await db.deleteChallenge(challengeId);
        throw new Error('Challenge expired');
      }
      
      // Find passkey by credential ID
      const passkey = await db.getPasskeyById(response.id);
      
      if (!passkey) {
        await db.deleteChallenge(challengeId);
        throw new Error('Passkey not found');
      }
      
      // Verify authentication
      let verification: VerifiedAuthenticationResponse;
      try {
        verification = await verifyAuthenticationResponse({
          response: response as unknown as Parameters<typeof verifyAuthenticationResponse>[0]['response'],
          expectedChallenge: challenge.challenge,
          expectedOrigin: config.relatedOrigins.length === 0
            ? config.origin
            : [config.origin, ...config.relatedOrigins.map(r => r.origin)],
          expectedRPID: config.relatedOrigins.length === 0
            ? config.rpId
            : [config.rpId, ...config.relatedOrigins.map(r => r.rpId)],
          credential: {
            id: passkey.credentialId,
            publicKey: passkey.publicKey,
            counter: passkey.counter,
            transports: passkey.transports,
          },
        } as VerifyAuthenticationResponseOpts);
      } catch (error) {
        log.error({ err: error }, 'Authentication verification failed');
        await db.deleteChallenge(challengeId);
        return { verified: false };
      }
      
      if (!verification.verified) {
        await db.deleteChallenge(challengeId);
        return { verified: false };
      }
      
      // Pitfall 1 mitigation: read FRESH BS/BE values from the assertion's verification
      // result, NOT from the stored `passkey` row (which may be stale).
      const freshBackedUp = verification.authenticationInfo.credentialBackedUp;
      const freshDeviceType = verification.authenticationInfo.credentialDeviceType;

      // Update counter
      await db.updatePasskeyCounter(
        passkey.credentialId,
        verification.authenticationInfo.newCounter
      );

      // BACKUP-02: persist the freshly-read backed_up only when it changed.
      // The adapter method is OPTIONAL — fall back silently if a custom adapter
      // doesn't implement it (project constraint: optional with internal fallback).
      if (freshBackedUp !== passkey.backedUp && db.updatePasskeyBackedUp) {
        await db.updatePasskeyBackedUp(passkey.credentialId, freshBackedUp);
      }

      // Clean up challenge
      await db.deleteChallenge(challengeId);

      return {
        verified: true,
        userId: passkey.userId,
        passkey,
        passkeyData: {
          backedUp: freshBackedUp,
          deviceType: freshDeviceType,
        },
      };
    },
  };
}
